import re

def run_bounded_sql(query: str, rows: list[dict[str, int]]) -> list[dict[str, int]]:
    # Define the regex pattern for the allowed SQL syntax
    pattern = r"^SELECT\s+(?P<columns>\*|[\w\s,]+)\s+FROM\s+rows\s*(WHERE\s+(?P<where_column>\w+)\s*(?P<operator>=|<|>|<=|>=|!=)\s*(?P<value>\d+))?\s*(LIMIT\s+(?P<limit>\d+))?$"

    # Check for disallowed keywords
    disallowed_keywords = ["DELETE", "UPDATE", "INSERT", "DROP", "ALTER", "CREATE", "PRAGMA", ";"]
    if any(keyword in query.upper() for keyword in disallowed_keywords):
        raise ValueError("Query contains disallowed keywords or syntax.")

    # Match the query against the pattern
    match = re.match(pattern, query.strip(), re.IGNORECASE)
    if not match:
        raise ValueError("Query does not match the allowed SELECT syntax.")

    # Extract components from the query
    columns = match.group("columns").strip()
    where_column = match.group("where_column")
    operator = match.group("operator")
    value = match.group("value")
    limit = match.group("limit")

    # Validate columns
    if columns != "*":
        selected_columns = [col.strip() for col in columns.split(",")]
        for col in selected_columns:
            if not all(col in row for row in rows):
                raise ValueError(f"Unknown column: {col}")
    else:
        selected_columns = list(rows[0].keys()) if rows else []

    # Filter rows based on WHERE clause
    if where_column:
        if not all(where_column in row for row in rows):
            raise ValueError(f"Unknown column in WHERE clause: {where_column}")

        value = int(value)
        if operator == "=":
            filtered_rows = [row for row in rows if row[where_column] == value]
        elif operator == "<":
            filtered_rows = [row for row in rows if row[where_column] < value]
        elif operator == ">":
            filtered_rows = [row for row in rows if row[where_column] > value]
        elif operator == "<=":
            filtered_rows = [row for row in rows if row[where_column] <= value]
        elif operator == ">=":
            filtered_rows = [row for row in rows if row[where_column] >= value]
        elif operator == "!=":
            filtered_rows = [row for row in rows if row[where_column] != value]
    else:
        filtered_rows = rows

    # Apply LIMIT clause
    if limit:
        limit = int(limit)
        filtered_rows = filtered_rows[:limit]

    # Select columns
    result = [{col: row[col] for col in selected_columns} for row in filtered_rows]

    return result

